
// =======================
// MENU HAMBURGER
// =======================
const hamburger = document.getElementById('hamburger');
const menu = document.getElementById('menu');

if (hamburger && menu) {
    hamburger.addEventListener('click', (e) => {
        e.stopPropagation();
        menu.classList.toggle('show');
    });

    document.addEventListener('click', (e) => {
        if (!menu.contains(e.target) && !hamburger.contains(e.target)) {
            menu.classList.remove('show');
        }
    });
}

// =======================
// RÉSERVER HÔTEL
// =======================
function reserver(nomHotel) {
    let message = "Bonjour 👋\n\n" +
        "Je souhaite réserver à " + nomHotel + ".\n\n" +
        "👤 Nom : \n" +
        "🛏️ Type de chambre : \n" +
        "📅 Date d'arrivée : \n" +
        "🌙 Nombre de nuits : \n" +
        "👥 Nombre de personnes : \n\n" +
        "Merci 🙏\n\n" +
        "----------------------------\n" +
        "Votre demande de réservation a bien été reçue.\n" +
        "⏳ Nous vérifions la disponibilité et revenons vers vous rapidement. ✅";

    let url = "https://wa.me/22598016927?text=" + encodeURIComponent(message);
    window.open(url, "_blank");
}

// =======================
// ENVOYER UN AVIS
// =======================
function envoyerAvis(nomHotel) {
    const message = `Bonjour 👋
Suite à mon séjour à ${nomHotel} :

⭐ Note : /5
💬 Votre avis :
Merci 🙏`;
    const url = "https://wa.me/22598016927?text=" + encodeURIComponent(message);
    window.open(url, "_blank");
}

// =======================
// OUVRIR ASSISTANCE
// =======================
function ouvrirAssistance() {
    const message = encodeURIComponent(
        "Bonjour Havenix CI 👋\n\nJe souhaite être assisté.\n\nMon besoin concerne :\n" +
        "🏨 Hébergement / hôtel\n🍽️ Restauration / bar\n🚗 Transport\n🔧 Services (coiffure, mécanique, etc.)\n" +
        "🏥 Santé / pharmacie\n📦 Autre\n\nMerci de me préciser votre besoin."
    );

    const url = "https://wa.me/22598016927?text=" + message;
    window.open(url, "_blank");
}

